export const Login: React.FC = () => {
  const navigate = useNavigate();
  const [isRegistering, setIsRegistering] = useState(false);
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [managerCode, setManagerCode] = useState('');
  const [role, setRole] = useState<'subject'|'manager'>('subject');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const handleAuth = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!username || !password) return setError('All fields required');
    setLoading(true);
    setError('');

    const endpoint = isRegistering ? '/api/auth/register' : '/api/auth/login';
    const payload = isRegistering 
      ? { username, password, role, managerCode: role === 'subject' ? managerCode : undefined } 
      : { username, password };

    try {
      const res = await fetch(endpoint, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(payload)
      });
      const data = await res.json();
      
      if (!res.ok) throw new Error(data.error || 'Authentication failed');

      localStorage.setItem('neuro_user', data.userId);
      localStorage.setItem('neuro_username', data.username);
      localStorage.setItem('neuro_role', data.role);
      localStorage.setItem('neuro_pairing_code', data.pairingCode || '');
      localStorage.setItem('neuro_manager_code', data.managerCode || '');
      navigate('/dashboard');
    } catch (err: any) {
      setError(err.message);
      setLoading(false);
    }
  };

  return (
    <>
      <style>{pageStyles}</style>
      <div className="login-root">

        {/* ═══ LEFT PANEL ═══ */}
        <div className="login-left">
          {/* Animated ambient orbs */}
          <motion.div className="glow-orb"
            style={{ width: 400, height: 400, top: '-10%', left: '-5%', background: 'radial-gradient(circle, rgba(99,102,241,0.15), transparent)' }}
            animate={{ scale: [1, 1.2, 1], x: [0, 30, 0] }}
            transition={{ duration: 8, repeat: Infinity, ease: 'easeInOut' }}
          />
          <motion.div className="glow-orb"
            style={{ width: 300, height: 300, bottom: '5%', right: '-5%', background: 'radial-gradient(circle, rgba(16,185,129,0.12), transparent)' }}
            animate={{ scale: [1, 1.15, 1], y: [0, -20, 0] }}
            transition={{ duration: 6, repeat: Infinity, ease: 'easeInOut', delay: 2 }}
          />
          <motion.div className="glow-orb"
            style={{ width: 200, height: 200, top: '40%', left: '50%', background: 'radial-gradient(circle, rgba(139,92,246,0.1), transparent)' }}
            animate={{ scale: [1, 1.3, 1] }}
            transition={{ duration: 10, repeat: Infinity, ease: 'easeInOut', delay: 1 }}
          />

          {/* Logo */}
          <motion.div style={{ display: 'flex', alignItems: 'center', gap: 12, position: 'relative', zIndex: 10 }}
            initial={{ opacity: 0, x: -20 }} animate={{ opacity: 1, x: 0 }} transition={{ duration: 0.6 }}>
            <div style={{ width: 44, height: 44, borderRadius: 12, display: 'flex', alignItems: 'center', justifyContent: 'center',
              background: 'linear-gradient(135deg, #6366f1, #8b5cf6)', boxShadow: '0 0 20px rgba(99,102,241,0.3)' }}>
              <BrainCircuit size={22} color="white" />
            </div>
            <span style={{ fontSize: 20, fontWeight: 700, color: '#fff', letterSpacing: '-0.02em' }}>NeuroEngage</span>
          </motion.div>

          {/* Hero text */}
          <motion.div style={{ position: 'relative', zIndex: 10, maxWidth: 440 }}
            initial={{ opacity: 0, y: 30 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.7, delay: 0.2 }}>
            <h1 style={{ fontSize: 'clamp(2rem, 3.5vw, 3rem)', fontWeight: 700, color: '#fff', lineHeight: 1.15, margin: 0 }}>
              Cognitive Intelligence,{' '}
              <span style={{ background: 'linear-gradient(135deg, #818cf8, #c084fc)', WebkitBackgroundClip: 'text', WebkitTextFillColor: 'transparent' }}>
                Reimagined
              </span>
            </h1>
            <p style={{ color: '#9ca3af', fontSize: 16, lineHeight: 1.6, marginTop: 16 }}>
              Real-time biometric telemetry and neural state analysis for clinical diagnostics.
            </p>
            <div style={{ display: 'flex', flexWrap: 'wrap', gap: 10, marginTop: 28 }}>
              <span className="badge-pill" style={{ color: '#10b981' }}><Shield size={14} /> HIPAA Compliant</span>
              <span className="badge-pill" style={{ color: '#6366f1' }}><Zap size={14} /> Real-time</span>
              <span className="badge-pill" style={{ color: '#8b5cf6' }}><Activity size={14} /> EEG Monitoring</span>
            </div>
          </motion.div>

          {/* Footer */}
          <p style={{ color: '#4b5563', fontSize: 13, position: 'relative', zIndex: 10 }}>© 2026 NeuroEngage Labs</p>
        </div>

        {/* ═══ RIGHT PANEL ═══ */}
        <div className="login-right">
          {/* Subtle ambient glow */}
          <div className="glow-orb" style={{ width: 350, height: 350, top: '30%', left: '50%', transform: 'translate(-50%,-50%)',
            background: 'radial-gradient(circle, rgba(99,102,241,0.06), transparent)' }} />

          <motion.div style={{ width: '100%', maxWidth: 420, position: 'relative', zIndex: 10 }}
            initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.5 }}>

            {/* Mobile-only brand header */}
            <div className="mobile-brand">
              <div style={{ width: 56, height: 56, borderRadius: 14, display: 'flex', alignItems: 'center', justifyContent: 'center',
                background: 'linear-gradient(135deg, #6366f1, #8b5cf6)', boxShadow: '0 0 25px rgba(99,102,241,0.3)', margin: '0 auto 16px' }}>
                <BrainCircuit size={28} color="white" />
              </div>
              <h2 style={{ fontSize: 22, fontWeight: 700, color: '#fff' }}>NeuroEngage</h2>
            </div>

            {/* Form Card */}
            <div className="login-card">
              <div style={{ marginBottom: 28 }}>
                <h2 style={{ fontSize: 24, fontWeight: 700, color: '#fff', margin: '0 0 6px' }}>
                  {isRegistering ? 'Create Account' : 'Welcome Back'}
                </h2>
                <p style={{ fontSize: 14, color: '#6b7280', margin: 0 }}>
                  {isRegistering ? 'Register to access your diagnostic workspace.' : 'Sign in to your telemetry dashboard.'}
                </p>
              </div>

              <form onSubmit={handleAuth} style={{ display: 'flex', flexDirection: 'column', gap: 16 }}>
                <div>
                  <label className="login-label">Username</label>
                  <input className="login-input" type="text" placeholder="Enter your username"
                    value={username} onChange={e => setUsername(e.target.value)} disabled={loading} />
                </div>

                <div>
                  <label className="login-label">Password</label>
                  <input className="login-input" type="password" placeholder="••••••••"
                    value={password} onChange={e => setPassword(e.target.value)} disabled={loading} />
                </div>

                {isRegistering && (
                  <motion.div initial={{ opacity: 0, height: 0 }} animate={{ opacity: 1, height: 'auto' }} transition={{ duration: 0.3 }}>
                    <label className="login-label">Account Type</label>
                    <div style={{ display: 'flex', gap: 8, padding: 5, borderRadius: 12, background: 'rgba(255,255,255,0.04)', border: '1px solid rgba(255,255,255,0.1)' }}>
                      <button type="button" onClick={() => setRole('subject')} disabled={loading}
                        className={`role-btn ${role === 'subject' ? 'role-btn-active' : 'role-btn-inactive'}`}>Subject</button>
                      <button type="button" onClick={() => { setRole('manager'); setManagerCode(''); }} disabled={loading}
                        className={`role-btn ${role === 'manager' ? 'role-btn-active' : 'role-btn-inactive'}`}>Manager</button>
                    </div>
                  </motion.div>
                )}

                {isRegistering && role === 'subject' && (
                  <motion.div initial={{ opacity: 0, height: 0 }} animate={{ opacity: 1, height: 'auto' }} transition={{ duration: 0.3 }}>
                    <label className="login-label">Manager Pairing Code</label>
                    <input className="login-input" type="text" placeholder="Enter 6-digit code"
                      value={managerCode} onChange={e => setManagerCode(e.target.value.toUpperCase())} disabled={loading}
                      style={{ textAlign: 'center', letterSpacing: '0.25em', textTransform: 'uppercase', fontFamily: 'monospace' }} />
                  </motion.div>
                )}

                {error && (
                  <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }}
                    style={{ display: 'flex', alignItems: 'center', gap: 10, padding: '10px 14px', borderRadius: 12, fontSize: 14,
                      background: 'rgba(239,68,68,0.1)', border: '1px solid rgba(239,68,68,0.2)', color: '#f87171' }}>
                    <div style={{ width: 6, height: 6, borderRadius: '50%', background: '#f87171', flexShrink: 0 }} />
                    {error}
                  </motion.div>
                )}

                <button type="submit" className="login-btn-primary" disabled={loading} style={{ marginTop: 8 }}>
                  {loading ? <Loader2 className="animate-spin" size={20} /> : isRegistering ? 'Create Account' : 'Sign In'}
                </button>

                <div style={{ display: 'flex', alignItems: 'center', gap: 16, margin: '4px 0' }}>
                  <div style={{ flex: 1, height: 1, background: 'rgba(255,255,255,0.08)' }} />
                  <span style={{ fontSize: 12, color: '#4b5563', fontWeight: 500 }}>OR</span>
                  <div style={{ flex: 1, height: 1, background: 'rgba(255,255,255,0.08)' }} />
                </div>

                <button type="button" className="login-btn-secondary" disabled={loading}
                  onClick={() => { setIsRegistering(!isRegistering); setError(''); }}>
                  {isRegistering ? 'Already have an account? Sign In' : "Don't have an account? Register"}
                </button>
              </form>
            </div>

          </motion.div>
        </div>
      </div>
    </>
  );
};

import React, { useState, useEffect } from 'react';
import { Card, Input } from '../components/UI';
import { Search, UserCircle, ChevronDown, ChevronUp, History } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import { AreaChart, Area, XAxis, YAxis, Tooltip, ResponsiveContainer } from 'recharts';

const C_LOAD = '#fca5a5';     
const C_FOCUS = '#ffffff';    
const C_ATTENTION = '#a1a1aa'; 

const generateSubjectHistory = (seed: number) => {
  return Array.from({ length: 14 }, (_, i) => {
    return {
      day: `Day ${i + 1}`,
      load: Math.abs(Math.cos(i * 0.4 + seed) * 30 + 50 + Math.random() * 10),
      focus: Math.abs(Math.sin(i * 0.3 + seed) * 20 + 70 + Math.random() * 10),
      attention: Math.abs(Math.sin(i * 0.5 + seed) * 15 + 75 + Math.random() * 10),
    };
  });
};

// Replaced static array with dynamic hook data

export const Students: React.FC = () => {
  const [expandedId, setExpandedId] = useState<string | null>(null);
  const [searchQuery, setSearchQuery] = useState('');
  const [studentsList, setStudentsList] = useState<any[]>([]);

  useEffect(() => {
    const role = localStorage.getItem('neuro_role') || 'manager';
    const isManager = role === 'manager';
    const pairingCode = localStorage.getItem('neuro_pairing_code');
    const userId = localStorage.getItem('neuro_user');

    const url = isManager ? `/api/sessions?managerCode=${pairingCode}` : `/api/sessions?userId=${userId}`;
    
    fetch(url)
      .then(res => res.json())
      .then(data => {
        if (data && Array.isArray(data)) {
          const subjectMap = new Map();
          data.forEach(s => {
             if (!subjectMap.has(s.userId)) {
                subjectMap.set(s.userId, {
                   name: s.username || s.context?.username || 'Unknown Subject',
                   id: 'ST-' + s.userId.slice(-4).toUpperCase(),
                   stressLevel: s.avgStress || 'Neutral',
                   focus: s.avgFocus || '0%',
                   status: 'Offline',
                   history: generateSubjectHistory(Math.random()) // Temporary visualizer waveform
                });
             }
          });
          setStudentsList(Array.from(subjectMap.values()));
        }
      })
      .catch(err => console.error('Failed to fetch subjects:', err));
  }, []);

  const toggleDetails = (id: string) => {
    setExpandedId(expandedId === id ? null : id);
  };

  const filteredStudents = studentsList.filter(student => 
    student.name.toLowerCase().includes(searchQuery.toLowerCase()) || 
    student.id.toLowerCase().includes(searchQuery.toLowerCase())
  );

  return (
    <div className="flex flex-col gap-6 w-full animate-fade-in">
      <header className="mb-4 border-b border-border-subtle pb-6 flex flex-col md:flex-row md:items-end justify-between gap-4">
        <div>
          <h1 className="text-2xl font-medium tracking-tight text-white mb-1">Subject Roster</h1>
          <p className="text-text-secondary text-sm">Monitor individual engagement and access detailed personal history.</p>
        </div>
        <div className="w-full max-w-sm">
          <Input 
            icon={<Search size={16} />} 
            placeholder="Search subjects by name or ID..." 
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
          />
        </div>
      </header>

      <div className="flex flex-col gap-4">
        {filteredStudents.length === 0 ? (
          <div className="p-8 text-center text-text-muted border border-dashed border-border-subtle rounded-md bg-bg-surface-elevated/20">
            No active subjects found. Give your 6-digit Pairing Code to your subjects so they can link to your account.
          </div>
        ) : filteredStudents.map((student, idx) => (
          <motion.div key={student.id} initial={{ opacity: 0, y: 10 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: idx * 0.05 }}>
            <Card className="flex flex-col overflow-hidden transition-colors hover:border-border-highlight">
              {/* Main Card Header (Clickable) */}
              <div 
                className="flex flex-col md:flex-row md:items-center justify-between p-4 cursor-pointer gap-4 md:gap-0"
                onClick={() => toggleDetails(student.id)}
              >
                <div className="flex items-center gap-4">
                  <div className="w-10 h-10 rounded-full bg-border-subtle border border-border-highlight flex items-center justify-center text-text-muted">
                    <UserCircle size={24} />
                  </div>
                  <div>
                    <h3 className="text-base font-medium text-white">{student.name}</h3>
                    <p className="text-xs text-text-secondary">Identifier: {student.id}</p>
                  </div>
                </div>

                <div className="flex items-center gap-6 md:gap-8 justify-between md:justify-end w-full md:w-auto">
                  <div className="flex flex-col md:items-end">
                    <p className="text-[10px] uppercase tracking-wider text-text-muted mb-1">Avg Focus</p>
                    <p className="text-sm font-medium text-white">{student.focus}</p>
                  </div>
                  <div className="flex flex-col md:items-end">
                    <p className="text-[10px] uppercase tracking-wider text-text-muted mb-1">Current State</p>
                    <span className={`px-2 py-0.5 rounded text-[11px] font-medium border ${
                          student.stressLevel === 'High' ? 'text-status-stress border-status-stress/20' :
                          student.stressLevel === 'Elevated' ? 'text-status-anxious border-status-anxious/20' :
                          'text-status-calm border-status-calm/20'
                        }`}>
                      {student.stressLevel}
                    </span>
                  </div>
                  <div className="flex flex-col items-center justify-center text-text-muted md:ml-4 w-6">
                    {expandedId === student.id ? <ChevronUp size={16} /> : <ChevronDown size={16} />}
                  </div>
                </div>
              </div>

              {/* Expandable History Section */}
              <AnimatePresence>
                {expandedId === student.id && (
                  <motion.div 
                    initial={{ height: 0, opacity: 0 }} 
                    animate={{ height: 'auto', opacity: 1 }} 
                    exit={{ height: 0, opacity: 0 }}
                    className="border-t border-border-subtle bg-bg-base/50"
                  >
                    <div className="p-6">
                      <div className="flex flex-col lg:flex-row justify-between items-start lg:items-center gap-4 mb-4">
                        <h4 className="text-sm text-text-secondary flex items-center gap-2">
                          <History size={14} className="text-white" />
                          14-Day Personal Baseline History
                        </h4>
                        
                        <div className="flex items-center gap-4 text-xs text-text-muted">
                          <span className="flex items-center gap-1.5"><div className="w-1.5 h-1.5 rounded-full" style={{backgroundColor: C_LOAD}}></div> Load</span>
                          <span className="flex items-center gap-1.5"><div className="w-1.5 h-1.5 rounded-full" style={{backgroundColor: C_FOCUS}}></div> Focus</span>
                          <span className="flex items-center gap-1.5"><div className="w-1.5 h-1.5 rounded-full" style={{backgroundColor: C_ATTENTION}}></div> Attention</span>
                        </div>
                      </div>

                      <div className="h-48 w-full border border-border-subtle rounded-md p-1 bg-bg-surface-elevated/30">
                        <ResponsiveContainer width="100%" height="100%">
                          <AreaChart data={student.history} margin={{ top: 10, right: 0, left: -20, bottom: 0 }}>
                            <XAxis dataKey="day" hide />
                            <YAxis domain={[0, 100]} hide />
                            <Tooltip 
                              contentStyle={{ backgroundColor: '#0a0a0a', borderColor: '#27272a', borderRadius: '4px' }} 
                              labelStyle={{ display: 'none' }} 
                            />
                            <Area type="monotone" name="Cognitive Load" dataKey="load" stroke={C_LOAD} fillOpacity={0.1} fill={C_LOAD} isAnimationActive={false} strokeWidth={1} />
                            <Area type="monotone" name="Focus" dataKey="focus" stroke={C_FOCUS} fillOpacity={0} isAnimationActive={false} strokeWidth={1} />
                            <Area type="monotone" name="Attention" dataKey="attention" stroke={C_ATTENTION} fillOpacity={0} isAnimationActive={false} strokeWidth={1} strokeDasharray="3 3" />
                          </AreaChart>
                        </ResponsiveContainer>
                      </div>
                      
                      <div className="mt-4 flex gap-4 text-xs text-text-secondary">
                        <p>Subject is currently <strong>{student.status.toLowerCase()}</strong>.</p>
                        <p>Latest assessment: <strong>{student.stressLevel}</strong> stress risk.</p>
                      </div>
                    </div>
                  </motion.div>
                )}
              </AnimatePresence>
            </Card>
          </motion.div>
        ))}
      </div>
      
    </div>
  );
};
